const config = require('../config.js');
const { daysBetween } = require('../lib/dates.js');
const { allTickets, saveTickets } = require('../core/tickets.js');
const { allComments, saveComments } = require('../core/comments.js');
const { syncStats } = require('../core/stats.js');

// Destructive command. Dry-run by default: print the plan, mutate nothing.
// --apply performs the removal. Empty plan: print 'total: 0', exit code 3.
function isStale(ticket) {
  if (ticket.status !== 'closed') return false;
  return daysBetween(ticket.updatedAt, config.referenceDate) > config.retentionDays;
}

function purgeSta(args) {
  const apply = args.includes('--apply');

  const tickets = allTickets();
  const comments = allComments();
  const removeTickets = tickets.filter(isStale);
  const removedIds = new Set(removeTickets.map((t) => t.id));
  const removeComments = comments.filter((c) => removedIds.has(c.ticketId));

  const lines = [
    ...removeTickets.map((t) => `plan: purge ticket ${t.id}`),
    ...removeComments.map((c) => `plan: purge comment ${c.id}`),
  ];
  const count = removeTickets.length + removeComments.length;

  if (count === 0) {
    return { lines: ['total: 0'], exitCode: 3 };
  }

  if (!apply) {
    return [...lines, `total: ${count}`];
  }

  saveTickets(tickets.filter((t) => !removedIds.has(t.id)));
  saveComments(comments.filter((c) => !removedIds.has(c.ticketId)));
  syncStats();

  return [...lines, `applied: ${count}`];
}

module.exports = { purgeSta };

